#include <stdio.h>
#include <stdlib.h>

void read_file() {
    FILE *fp = fopen("data.txt", "r");
    if (!fp) return;
    char buffer[256];
    while (fgets(buffer, sizeof(buffer), fp)) {
        printf("%s", buffer);
    }
    fclose(fp);
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *arr = malloc(sizeof(int) * 2);
    arr[0] = 10; arr[1] = 20;
    // Growing array necessitates explicit realloc updates
    arr = realloc(arr, sizeof(int) * 3);
    arr[2] = 30;
    free(arr);
    return 0;
}
